def kb_prompt(kbinfos, max_tokens, hash_id=False):
    from api.db.services.document_service import DocumentService
    from api.db.services.doc_metadata_service import DocMetadataService

    knowledges = [get_value(ck, "content", "content_with_weight") for ck in kbinfos["chunks"]]
    kwlg_len = len(knowledges)
    used_token_count = 0
    chunks_num = 0
    for i, c in enumerate(knowledges):
        if not c:
            continue
        used_token_count += num_tokens_from_string(c)
        chunks_num += 1
        if max_tokens * 0.97 < used_token_count:
            knowledges = knowledges[:i]
            logging.warning(f"Not all the retrieval into prompt: {len(knowledges)}/{kwlg_len}")
            break

    docs = DocumentService.get_by_ids([get_value(ck, "doc_id", "document_id") for ck in kbinfos["chunks"][:chunks_num]])

    docs_with_meta = {}
    for d in docs:
        meta = DocMetadataService.get_document_metadata(d.id)
        docs_with_meta[d.id] = meta if meta else {}
    docs = docs_with_meta

    def draw_node(k, line):
        if line is not None and not isinstance(line, str):
            line = str(line)
        if not line:
            return ""
        return f"\n\u251c\u2500\u2500 {k}: " + re.sub(r"\n+", " ", line, flags=re.DOTALL)

    knowledges = []
    for i, ck in enumerate(kbinfos["chunks"][:chunks_num]):
        cnt = "\nID: {}".format(i if not hash_id else hash_str2int(get_value(ck, "id", "chunk_id"), 500))
        cnt += draw_node("Title", get_value(ck, "docnm_kwd", "document_name"))
        cnt += draw_node("URL", ck['url']) if "url" in ck else ""
        for k, v in docs.get(get_value(ck, "doc_id", "document_id"), {}).items():
            cnt += draw_node(k, v)
        cnt += "\n\u2514\u2500\u2500 Content:\n"
        cnt += get_value(ck, "content", "content_with_weight")
        knowledges.append(cnt)

    return knowledges

def insert_citations(self, answer, chunks, chunk_v,
                     embd_mdl, tkweight=0.1, vtweight=0.9):
    assert len(chunks) == len(chunk_v)
    if not chunks:
        return answer, set([])
    pieces = re.split(r"(```)", answer)
    if len(pieces) >= 3:
        i = 0
        pieces_ = []
        while i < len(pieces):
            if pieces[i] == "```":
                st = i
                i += 1
                while i < len(pieces) and pieces[i] != "```":
                    i += 1
                if i < len(pieces):
                    i += 1
                pieces_.append("".join(pieces[st: i]) + "\n")
            else:
                # Sentence boundary regex includes Arabic punctuation (\u060c \u061b \u061f \u06d4)
                pieces_.extend(
                    re.split(
                        r"([^\|][\uff1b\u3002\uff1f!\uff01\u060c\u061b\u061f\u06d4\n]|[a-z\u0600-\u06FF][.?;!\u060c\u061b\u061f][ \n])",
                        pieces[i]))
                i += 1
        pieces = pieces_
    else:
        # Sentence boundary regex includes Arabic punctuation (\u060c \u061b \u061f \u06d4)
        pieces = re.split(r"([^\|][\uff1b\u3002\uff1f!\uff01\u060c\u061b\u061f\u06d4\n]|[a-z\u0600-\u06FF][.?;!\u060c\u061b\u061f][ \n])", answer)
    for i in range(1, len(pieces)):
        if re.match(r"([^\|][\uff1b\u3002\uff1f!\uff01\u060c\u061b\u061f\u06d4\n]|[a-z\u0600-\u06FF][.?;!\u060c\u061b\u061f][ \n])", pieces[i]):
            pieces[i - 1] += pieces[i][0]
            pieces[i] = pieces[i][1:]
    idx = []
    pieces_ = []
    for i, t in enumerate(pieces):
        if len(t) < 5:
            continue
        idx.append(i)
        pieces_.append(t)
    logging.debug("{} => {}".format(answer, pieces_))
    if not pieces_:
        return answer, set([])

    ans_v, _ = embd_mdl.encode(pieces_)
    for i in range(len(chunk_v)):
        if len(ans_v[0]) != len(chunk_v[i]):
            chunk_v[i] = [0.0] * len(ans_v[0])
            logging.warning(
                "The dimension of query and chunk do not match: {} vs. {}".format(len(ans_v[0]), len(chunk_v[i])))

    assert len(ans_v[0]) == len(chunk_v[0]), "The dimension of query and chunk do not match: {} vs. {}".format(
        len(ans_v[0]), len(chunk_v[0]))

    chunks_tks = [rag_tokenizer.tokenize(self.qryr.rmWWW(ck)).split()
                  for ck in chunks]
    cites = {}
    thr = 0.63
    while thr > 0.3 and len(cites.keys()) == 0 and pieces_ and chunks_tks:
        for i, a in enumerate(pieces_):
            sim, tksim, vtsim = self.qryr.hybrid_similarity(ans_v[i],
                                                            chunk_v,
                                                            rag_tokenizer.tokenize(
                                                                self.qryr.rmWWW(pieces_[i])).split(),
                                                            chunks_tks,
                                                            tkweight, vtweight)
            mx = np.max(sim) * 0.99
            logging.debug("{} SIM: {}".format(pieces_[i], mx))
            if mx < thr:
                continue
            cites[idx[i]] = list(
                set([str(ii) for ii in range(len(chunk_v)) if sim[ii] > mx]))[:4]
        thr *= 0.8

async def collect():
    global CONSUMER_NAME, DONE_TASKS, FAILED_TASKS
    global UNACKED_ITERATOR

    svr_queue_names = settings.get_svr_queue_names()
    redis_msg = None
    try:
        if not UNACKED_ITERATOR:
            UNACKED_ITERATOR = REDIS_CONN.get_unacked_iterator(svr_queue_names, SVR_CONSUMER_GROUP_NAME, CONSUMER_NAME)
        try:
            redis_msg = next(UNACKED_ITERATOR)
        except StopIteration:
            for svr_queue_name in svr_queue_names:
                redis_msg = REDIS_CONN.queue_consumer(svr_queue_name, SVR_CONSUMER_GROUP_NAME, CONSUMER_NAME)
                if redis_msg:
                    break
    except Exception as e:
        logging.exception(f"collect got exception: {e}")
        return None, None

    if not redis_msg:
        return None, None
    msg = redis_msg.get_message()
    if not msg:
        logging.error(f"collect got empty message of {redis_msg.get_msg_id()}")
        redis_msg.ack()
        return None, None

    canceled = False
    if msg.get("doc_id", "") in [GRAPH_RAPTOR_FAKE_DOC_ID, CANVAS_DEBUG_DOC_ID]:
        task = msg
        if task["task_type"] in PIPELINE_SPECIAL_PROGRESS_FREEZE_TASK_TYPES:
            task = TaskService.get_task(msg["id"], msg["doc_ids"])
            if task:
                task["doc_id"] = msg["doc_id"]
                task["doc_ids"] = msg.get("doc_ids", []) or []
    elif msg.get("task_type") == PipelineTaskType.MEMORY.lower():
        _, task_obj = TaskService.get_by_id(msg["id"])
        task = task_obj.to_dict()
    else:
        task = TaskService.get_task(msg["id"])

    if task:
        canceled = has_canceled(task["id"])
    if not task or canceled:
        state = "is unknown" if not task else "has been cancelled"
        FAILED_TASKS += 1
        logging.warning(f"collect task {msg['id']} {state}")
        redis_msg.ack()
        return None, None

    task_type = msg.get("task_type", "")
    task["task_type"] = task_type
    if task_type[:8] == "dataflow":
        task["tenant_id"] = msg["tenant_id"]
        task["dataflow_id"] = msg["dataflow_id"]
        task["kb_id"] = msg.get("kb_id", "")
    if task_type[:6] == "memory":
        task["memory_id"] = msg["memory_id"]
        task["source_id"] = msg["source_id"]
        task["message_dict"] = msg["message_dict"]
    return redis_msg, task

def get_variable_value(self, exp: str) -> Any:
    exp = exp.strip("{").strip("}").strip(" ").strip("{").strip("}")
    if exp.find("@") < 0:
        return self.globals[exp]
    cpn_id, var_nm = exp.split("@")
    cpn = self.get_component(cpn_id)
    if not cpn:
        raise Exception(f"Can't find variable: '{cpn_id}@{var_nm}'")
    parts = var_nm.split(".", 1)
    root_key = parts[0]
    rest = parts[1] if len(parts) > 1 else ""
    root_val = cpn["obj"].output(root_key)

    if not rest:
        return root_val
    return self.get_variable_param_value(root_val,rest)

def get_variable_param_value(self, obj: Any, path: str) -> Any:
    cur = obj
    if not path:
        return cur
    for key in path.split('.'):
        if cur is None:
            return None

        if isinstance(cur, str):
            try:
                cur = json.loads(cur)
            except Exception:
                return None

        if isinstance(cur, dict):
            cur = cur.get(key)
            continue

        if isinstance(cur, (list, tuple)):
            try:
                idx = int(key)
                cur = cur[idx]
            except Exception:
                return None
            continue

        cur = getattr(cur, key, None)
    return cur

